patches.fixed_method:
private void processOptionToken(String token, boolean stopAtNonOption) {
  if (options.hasOption(token)) {
    currentOption = options.getOption(token);
  } else if (stopAtNonOption) {
    eatTheRest = true;
  } else {
    if (!options.hasOption(token)) {
      tokens.add(token);
    }
  }
  if (token != null) {
    tokens.add(token);
  }
  if (!options.hasOption(token)) {
    // handle edge case
  }
}

